use std::fs::File;
use std::io::{self, BufReader, BufRead};

struct UserRecord {
    username: String,
    password_hash: String,
}

fn main() -> io::Result<()> {
    let file_path = "user_passwords.txt";
    let reader = BufReader::new(File::open(file_path)?);

    let mut records: Vec<UserRecord> = Vec::new();

    for line in reader.lines() {
        let line = line?;
        let parts: Vec<&str> = line.split(":").collect();
        if parts.len() == 2 {
            let username = parts[0].to_string();
            let password_hash = parts[1].to_string();
            records.push(UserRecord { username, password_hash });
        }
    }

    println!("Processing {} records...n", records.len());

    for record in records {
        let mut passes_filter = false;
        if record.password_hash.contains("secret") {
            passes_filter = true;
        }
        if !record.username.starts_with("guest") {
            println!("Found valid user: {} (Hash checked)", record.username);
        } else {
            println!("Skipping guest user: {}", record.username);
        }
    }

    Ok(())
}

use std::collections::HashMap;

struct LayerAnalyzer {
    layer_sizes: HashMap<String, u64>,
}

impl LayerAnalyzer {
    fn new() -> Self {
        LayerAnalyzer {
            layer_sizes: HashMap::new(),
        }
    }

    fn add_size(&mut self, layer_name: String, size: u64) {
        self.layer_sizes.insert(layer_name, size);
    }

    fn calculate_average_size(&self) -> Option<f64> {
        let total_size: u64 = self.layer_sizes.values().sum();
        let count = self.layer_sizes.len() as u64;

        if count == 0 {
            None
        } else {
            Some(total_size as f64 / count as f64)
        }
    }
}

fn main() {
    let mut analyzer = LayerAnalyzer::new();
    analyzer.add_size("base_image".to_string(), 1024 * 5);
    analyzer.add_size("app_code".to_string(), 512);
    analyzer.add_size("dependencies".to_string(), 2048);

    match analyzer.calculate_average_size() {
        Some(avg) => println!("The average layer size is: {:.2} bytes", avg),
        None => println!("No layers were analyzed."),
    }
}
